  }

  @protected
  void sse_encode_volume_info_dto(
    VolumeInfoDto self,
    SseSerializer serializer,
  ) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_String(self.mountPath, serializer);
    sse_encode_String(self.device, serializer);
    sse_encode_String(self.fsType, serializer);
    sse_encode_u_64(self.totalBytes, serializer);
    sse_encode_u_64(self.usedBytes, serializer);
    sse_encode_u_64(self.availableBytes, serializer);
  }
